109	/// Resolve positional and flag args into a `DotSpec` ready for `collect_ids`.
110	///
111	/// Handles: dot notation parsing, flag vs positional precedence,
112	/// count-means-total semantics (subtracts 1 for anchor).
113	pub fn resolve_spec(
114	    pos_rev: Option<&str>,
115	    pos_count: Option<usize>,
116	    flag_rev: &str,
117	    flag_limit: Option<usize>,
118	    default_rev: &str,
119	) -> DotSpec {
120	    let flag_rev_set = flag_rev != default_rev;
121	    let rev_str = if flag_rev_set {
122	        flag_rev
123	    } else {
124	        pos_rev.unwrap_or(default_rev) // OK: positional absent → fall back to CLI default
125	    };
126	    let mut spec = parse_dot_rev(rev_str);
127	
128	    let count = if flag_limit.is_some() {
129	        flag_limit
130	    } else {
131	        pos_count
132	    };
133	
134	    if let Some(c) = count {
135	        let n = c.saturating_sub(1);
136	        let both_open = spec.desc_count.is_none() && spec.anc_count.is_none();
137	        if both_open {
138	            // Split budget across both sides: ancestors get the extra
139	            let desc_n = n / 2;
140	            let anc_n = n - desc_n;
141	            spec.desc_count = Some(desc_n);
142	            spec.anc_count = Some(anc_n);
143	        } else {
144	            if spec.desc_count.is_none() {
145	                spec.desc_count = Some(n);
146	            }
147	            if spec.anc_count.is_none() {
148	                spec.anc_count = Some(n);
149	            }
150	            // bare `x 5` → treat as `x.. 5` (ancestors)
151	            if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
152	                spec.anc_count = Some(n);
153	            }
154	        }
155	    }
156	
157	    spec
158	}
