318	/// Collect commit IDs for `..x..` (both directions) or any dot notation.
319	///
320	/// Returns `(commit_ids, anchor_index)` — the IDs in display order
321	/// (descendants closest to anchor, anchor, ancestors closest to anchor)
322	/// and the index of the anchor commit within the list.
323	///
324	/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
325	/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
326	pub fn collect_ids(
327	    workspace: &Workspace,
328	    repo: &Arc<ReadonlyRepo>,
329	    rev: &str,
330	    desc_count: Option<usize>,
331	    anc_count: Option<usize>,
332	) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
333	    let anchor_ids = resolve_revset(workspace, repo, rev)?;
334	    if anchor_ids.is_empty() {
335	        return Err(format!("no commit found for revision '{rev}'").into());
336	    }
337	    let anchor_id = &anchor_ids[0];
338	    let root_commit_id = repo.store().root_commit_id().clone();
339	
340	    // Descendants (closest to anchor)
341	    let mut desc_ids: Vec<CommitId> = Vec::new();
342	    if desc_count != Some(0) {
343	        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
344	        desc_ids = descendant_ids
345	            .into_iter()
346	            .filter(|id| *id != root_commit_id && *id != *anchor_id)
347	            .collect();
348	        if let Some(n) = desc_count {
349	            let start = desc_ids.len().saturating_sub(n);
350	            desc_ids = desc_ids[start..].to_vec();
351	        }
352	    }
353	
354	    // Ancestors (closest to anchor)
355	    let mut anc_ids: Vec<CommitId> = Vec::new();
356	    if anc_count != Some(0) {
357	        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
358	        let limit = anc_count.unwrap_or(usize::MAX); // OK: no --ancestors limit → unbounded
359	        let mut count = 0;
360	        for commit_id in ancestor_ids {
361	            if commit_id == root_commit_id || commit_id == *anchor_id {
362	                continue;
363	            }
364	            anc_ids.push(commit_id);
365	            count += 1;
366	            if count >= limit {
367	                break;
368	            }
369	        }
370	    }
371	
372	    let anchor_index = desc_ids.len();
373	    let mut result = desc_ids;
374	    result.push(anchor_id.clone());
375	    result.extend(anc_ids);
376	    Ok((result, anchor_index))
377	}
