480	/// Parse and evaluate a revset string, returning commit IDs.
481	pub fn resolve_revset(
482	    workspace: &Workspace,
483	    repo: &Arc<ReadonlyRepo>,
484	    revset_str: &str,
485	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
486	    let aliases_map = RevsetAliasesMap::new();
487	    let fileset_aliases_map = FilesetAliasesMap::new();
488	    let extensions = RevsetExtensions::default();
489	    let workspace_root = workspace.workspace_root().to_path_buf();
490	    let path_converter = RepoPathUiConverter::Fs {
491	        cwd: workspace_root.clone(),
492	        base: workspace_root,
493	    };
494	    let workspace_name = workspace.workspace_name();
495	    let workspace_ctx = RevsetWorkspaceContext {
496	        path_converter: &path_converter,
497	        workspace_name,
498	    };
499	    let context = RevsetParseContext {
500	        aliases_map: &aliases_map,
501	        local_variables: HashMap::new(),
502	        user_email: "",
503	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
504	        default_ignored_remote: None,
505	        fileset_aliases_map: &fileset_aliases_map,
506	        use_glob_by_default: false,
507	        extensions: &extensions,
508	        workspace: Some(workspace_ctx),
509	    };
510	
511	    let mut diagnostics = RevsetDiagnostics::new();
512	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
513	
514	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
515	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
516	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
517	    let revset = resolved.evaluate(repo.as_ref())?;
518	
519	    let mut commit_ids = Vec::new();
520	    for result in revset.iter() {
521	        commit_ids.push(result?);
522	    }
523	    Ok(commit_ids)
524	}
